import React, { useState } from 'react';
import api from '../api/axiosConfig';
import ReactMarkdown from 'react-markdown';
import { motion, AnimatePresence } from 'framer-motion';
import { Terminal, Cpu, Download, ShieldCheck, Zap } from 'lucide-react';
import toast from 'react-hot-toast';

const GeneratePage = () => {
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);

  const handleGenerate = async (e) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setResult(null); // Clear previous result for a fresh scan
    
    try {
      const response = await api.post('/portfolio/generate', { query });
      // The backend returns { status: "success", data: { summary, holdings, rationale } }
      setResult(response.data.data);
      toast.success("STRATEGY_SYNTHESIS_COMPLETE");
    } catch (err) {
      console.error("Synthesis Node Failure:", err);
      toast.error("SYSTEM_FAILURE: AGENTIC_DEBATE_INTERRUPTED");
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadPDF = async () => {
    try {
      const response = await api.post('/portfolio/export', result, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Finify_Strategy_${Date.now()}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      toast.error("PDF_EXPORT_FAILED");
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-10 animate-in fade-in duration-500">
      {/* 🏛️ Header Section */}
      <div className="border-b border-white/5 pb-6">
        <h1 className="flex items-center gap-3 text-2xl font-bold tracking-tighter text-white">
          <Cpu className="text-emerald-500" size={24} />
          STRATEGY_ENGINE_v3.2
        </h1>
        <p className="text-[10px] text-white/30 uppercase tracking-widest mt-1">
          Active Node: Agentic_RAG_Cluster // Corpus: NSE_BSE_2026
        </p>
      </div>

      {/* ⌨️ Input Section */}
      <form onSubmit={handleGenerate} className="relative group">
        <input 
          className="w-full bg-[#1a1a1a] border border-white/10 p-6 pr-40 rounded-xl text-white placeholder:text-white/20 focus:outline-none focus:border-emerald-500/50 focus:ring-1 focus:ring-emerald-500/20 transition-all font-mono"
          placeholder="DESCRIBE_GOAL: e.g., Aggressive growth in Indian EV sector for 3 years..."
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          disabled={loading}
        />
        <button 
          type="submit"
          disabled={loading || !query.trim()}
          className="absolute right-3 top-1/2 -translate-y-1/2 bg-emerald-500 text-black px-8 py-3 rounded-lg font-bold text-[10px] tracking-widest uppercase hover:bg-emerald-400 disabled:opacity-50 disabled:grayscale transition-all"
        >
          {loading ? "PROCESSING..." : "INITIALIZE"}
        </button>
      </form>

      {/* 🚀 Output / Loading Area */}
      <AnimatePresence mode="wait">
        {loading && (
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
            className="flex flex-col items-center py-24 space-y-6"
          >
            <div className="relative">
              <div className="w-16 h-16 border-2 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin" />
              <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-emerald-500 animate-pulse" size={20} />
            </div>
            <div className="text-center space-y-2">
              <p className="text-emerald-500 text-[10px] tracking-[0.5em] font-bold uppercase animate-pulse">
                Agentic_Debate_In_Progress
              </p>
              <p className="text-white/20 text-[9px] font-mono">
                CROSS_REFERENCING_STOCKS_JSON + YFINANCE_LIVE_DATA
              </p>
            </div>
          </motion.div>
        )}

        {result && !loading && (
          <motion.div 
            initial={{ y: 20, opacity: 0 }} 
            animate={{ y: 0, opacity: 1 }}
            className="space-y-6"
          >
            {/* Top Toolbar */}
            <div className="flex justify-between items-center bg-emerald-500/5 border border-emerald-500/10 p-4 rounded-xl">
              <div className="flex items-center gap-3">
                <ShieldCheck className="text-emerald-500" size={18} />
                <span className="text-[10px] text-emerald-500 uppercase font-bold tracking-widest">Strategy_Verified_By_Risk_Agent</span>
              </div>
              <button 
                onClick={handleDownloadPDF}
                className="flex items-center gap-2 text-[10px] bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-500 px-4 py-2 rounded-lg transition-all uppercase font-bold"
              >
                <Download size={14} /> Export_Institutional_Report
              </button>
            </div>

            {/* Content Grid */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {/* Summary Block */}
              <div className="md:col-span-3 p-6 bg-[#1a1a1a] border border-white/10 rounded-2xl">
                <h3 className="text-emerald-500 mb-4 text-[10px] font-bold uppercase tracking-widest flex items-center gap-2">
                  <Terminal size={14} /> 01_Executive_Summary
                </h3>
                <p className="text-white/70 text-sm leading-relaxed italic border-l-2 border-emerald-500/20 pl-4">
                  {result.summary}
                </p>
              </div>

              {/* Holdings Block */}
              <div className="p-6 bg-[#1a1a1a] border border-white/10 rounded-2xl">
                <h3 className="text-emerald-500 mb-4 text-[10px] font-bold uppercase tracking-widest">02_Allocations</h3>
                <article className="prose prose-invert prose-emerald prose-sm max-w-none">
                  <ReactMarkdown>{result.holdings}</ReactMarkdown>
                </article>
              </div>

              {/* Rationale Block */}
              <div className="md:col-span-2 p-6 bg-[#1a1a1a] border border-white/10 rounded-2xl">
                <h3 className="text-emerald-500 mb-4 text-[10px] font-bold uppercase tracking-widest">03_Strategic_Rationale</h3>
                <article className="prose prose-invert prose-emerald prose-sm max-w-none">
                  <ReactMarkdown>{result.rationale}</ReactMarkdown>
                </article>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default GeneratePage;
